#include<bits/stdc++.h>
using namespace std;
int dp[100001], n, weight;
pair<int, int> a[200000];
int main() {
	cin >> n >> weight;
	for (int i = 1; i <= n; i++) {
		cin >> a[i].second>> a[i].first;
	}
	
	for (int i = 1; i <= n; i++) {
		for (int j = weight; j >=  a[i].second; j--) {
			dp[j] = max(a[i].first + dp[j - a[i].second], dp[j]);
		}
	}
	cout<<dp[weight];
	return 0;

}
